/* Suggested markup: <div class="uiwiki-radial-segment-loader" tabindex="0"><span>Radial Segment Loader</span></div> */
.uiwiki-radial-segment-loader {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-radial-segment-loader > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #ff9950;
  animation: radial_segment_loader 1.8s ease-in-out infinite alternate;
}
.uiwiki-radial-segment-loader:hover,
.uiwiki-radial-segment-loader:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes radial_segment_loader {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-radial-segment-loader, .uiwiki-radial-segment-loader > span { animation: none; transition: none; }
}
